export function useDebouncedComputed<T>(source: () => T, delay: (newVal: T, oldVal: T) => number | null) {
  const result = shallowRef(source())
  let timeout: NodeJS.Timeout | undefined
  watch(
    source,
    (newVal, oldVal) => {
      clearTimeout(timeout)
      const d = delay(newVal, oldVal)
      if (d == null) {
        result.value = newVal
      }
      else {
        timeout = setTimeout(() => {
          result.value = newVal
        }, d)
      }
    },
  )
  return computed<T>(() => result.value)
}

import type { Ref } from 'vue'
import { ref, watch } from 'vue'

export function useDeferredTrue(
  valueRef: Ref<any>,
  delay: number,
  shouldDelayRef: Ref<boolean>
): Ref<boolean> {
  if (!delay)
    return valueRef
  const delayedRef = ref(valueRef.value)
  let timerId: number | null = null
  watch(valueRef, (value) => {
    if (timerId !== null)
      window.clearTimeout(timerId)
    if (value === true) {
      if (shouldDelayRef && !shouldDelayRef.value) {
        delayedRef.value = true
      }
      else {
        timerId = window.setTimeout(() => {
          delayedRef.value = true
        }, delay)
      }
    }
    else {
      delayedRef.value = false
    }
  })
  return delayedRef
}

class CustomRefImpl<T, S = T> {
  public dep: Dep

  private readonly _get: ReturnType<CustomRefFactory<T, S>>['get']
  private readonly _set: ReturnType<CustomRefFactory<T, S>>['set']

  public readonly [ReactiveFlags.IS_REF] = true

  public _value: T = undefined!

  constructor(factory: CustomRefFactory<T, S>) {
    const dep = (this.dep = new Dep())
    const { get, set } = factory(dep.track.bind(dep), dep.trigger.bind(dep))
    this._get = get
    this._set = set
  }

  get value(): T {
    return (this._value = this._get())
  }

  set value(newVal: S) {
    this._set(newVal)
  }
}

