(event: KeyboardEvent) => {
  if (!props.keyNav) return

  const {code, shiftKey} = event

  if (code === CODE_LEFT || code === CODE_UP) {
    event.preventDefault()
    if (shiftKey) {
      focusFirst()
    } else {
      focusPrev()
    }
  } else if (code === CODE_RIGHT || code === CODE_DOWN) {
    event.preventDefault()
    if (shiftKey) {
      focusLast()
    } else {
      focusNext()
    }
