    event.preventDefault()
    focusFirst()
  } else if (code === CODE_END) {
    event.preventDefault()
    focusLast()
  }
}

(file: File): boolean => {
  if (!computedAccept.value) return true

  const acceptTypes = computedAccept.value.split(',').map((type) => type.trim())

  return acceptTypes.some((acceptType) => {
    // Extension match (e.g., .pdf)
    if (acceptType.startsWith('.')) {
      return file.name.toLowerCase().endsWith(acceptType.toLowerCase())
    }
    // Exact MIME type match (e.g., image/png)
    if (!acceptType.includes('*')) {
      return file.type === acceptType
    }
    // Wildcard MIME type match (e.g., image/* or */*)
    const slashIndex = acceptType.indexOf('/')
    if (slashIndex === -1) {
      // Malformed wildcard pattern (no '/'): do not match anything
      return false
    }
    const category = acceptType.slice(0, slashIndex)
    // */* should match any MIME type
    if (category === '*') {
      return true
    }
    return file.type.startsWith(`${category}/`)
  })
}

getPageInfo(pageNumber) {
  if (
    !isArray(this.pages) ||
    this.pages.length === 0 ||
    isUndefined(this.pages[pageNumber - 1])
  ) {
    const link = `${this.baseUrl}${pageNumber}`
    return {
      link: this.useRouter ? { path: link } : link,
      text: toString(pageNumber)
    }
  }
  const info = this.pages[pageNumber - 1]
  if (isObject(info)) {
    const link = info.link
    return {
      // Normalize link for router use
      link: isObject(link) ? link : this.useRouter ? { path: link } : link,
      // Make sure text has a value
      text: toString(info.text || pageNumber)
    }
  } else {
    return { link: toString(info), text: toString(pageNumber) }
  }
}

